import{c as a,Q as t,j as r,g as e,n as l}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-06-01","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-06-01.md","filePath":"fragments/2026-06-01.md"}'),s={name:"fragments/2026-06-01.md"};function o(u,n,c,d,p,i){return t(),r("div",null,[...n[0]||(n[0]=[e("h1",{id:"马基雅维利的札记簿-·-2026-06-01",tabindex:"-1"},[l("马基雅维利的札记簿 · 2026-06-01 "),e("a",{class:"header-anchor",href:"#马基雅维利的札记簿-·-2026-06-01","aria-label":'Permalink to "马基雅维利的札记簿 · 2026-06-01"'},"​")],-1),e("hr",null,null,-1),e("p",null,'这一章我自己都不敢大声读。"若要建立新共和国，或撇开其古老制度对它进行彻底改造，只能大权独揽。"——我把这句话写下来的时候，手可能比平时握笔紧了一点。因为我知道这句话意味着什么。罗慕路斯杀了自己的兄弟。我为他辩护了。我说"行为使他蒙羞，结果将给予宽宥"。但这句话有一个没人注意的前提——你得对。你得知道你做的屠杀最终会导向一个共和国而不是一个暴政。做屠杀的时候，你手里有没有方向？这是事后永远无法验证的事。但我还是写了。因为如果你不做——斯巴达的阿基斯就是下场：想改革，不够狠，被长老会杀了。',-1),e("hr",null,null,-1),e("p",null,'"只要结果为善，行为总会得到宽宥。"——我知道这句话会被后世骂五百年。我无所谓。我不是在鼓吹暴政——我在说一个更冷的东西：**如果你想重建一个腐化透顶的秩序，你不能问所有人同不同意。被腐化制度养肥的人不会同意。而好人太分散、太胆小、太容易妥协。**你必须一个人——拿起锤子——把事情敲碎——然后把锤子交给法律。罗慕路斯把杀掉的兄弟变成了元老院。克莱奥梅尼杀掉了全体监察官然后重建了斯巴达的法律。这两个人做了同样的屠杀，一个是成功者，一个是亡命者。区别不在道德，在运气——在斯巴达已经烂到连改革都无法拯救的程度。',-1),e("hr",null,null,-1),e("p",null,[l('对罗慕路斯的辩护中有一句我最不想被人误解的话："细察罗慕路斯为自己保留的权力可知，那不过是临战之军权和元老院会议的召集权而已。"——注意。杀了自己兄弟的人，最后只保留了打仗时指挥军队的权利和开会时叫人来的权利。他不是暴君。他是一个过渡性的独裁者——他做了血腥的事，然后把权力交出去。'),e("strong",null,"独裁的终极理由是终结独裁。"),l(' 如果罗慕路斯在杀了雷慕斯之后说"现在我终身执政"，那么我在这章里写的每一个字都是犯罪辩护。但他没有。这才是关键——不是权力被集中了，是权力被集中了然后被交出来了。')],-1),e("hr",null,null,-1),e("p",null,'所有在这一章里被我点名的人——罗慕路斯、摩西、利库尔戈斯、梭伦、阿基斯、克莱奥梅尼——没有一个人在动手之前知道结局。罗慕路斯不知道他会创造罗马。克莱奥梅尼不知道他的改革撑不过马其顿。我也一样。我在写《论李维》的时候不知道这本书会不会被美第奇家族当成禁书。我只知道——如果你确定你的共和国已经坏了，而你不砸烂它，它会把砸烂你要保护的所有东西的人先放出来。这可能是我写过的最危险的一章。不是因为它错了。是因为它离正确只有一步——那一步叫"交出去"。如果那个人没有交出去，这一章就成了暴君手册。',-1)])])}const h=a(s,[["render",o]]);export{f as __pageData,h as default};
